// Tiny HTMX-like helper for this app. Supports hx-get/hx-post, hx-target,
// hx-swap=innerHTML|outerHTML|beforeend|afterbegin, hx-indicator,
// GET form serialization, and hx-trigger="change".
(function () {
  // Re-execute <script> tags inserted via innerHTML (which doesn't run them).
  function runScripts(container) {
    container.querySelectorAll('script').forEach(function (old) {
      var s = document.createElement('script');
      Array.from(old.attributes).forEach(function (a) { s.setAttribute(a.name, a.value); });
      s.textContent = old.textContent;
      old.parentNode.replaceChild(s, old);
    });
  }

  function dispatch(name, detail) {
    document.body.dispatchEvent(new CustomEvent(name, { bubbles: true, detail: detail || {} }));
  }

  async function swapTarget(target, targetSel, swap, html, detail, el) {
    if (!target) return;
    if (swap === 'outerHTML') {
      target.outerHTML = html;
      const newEl = targetSel ? document.querySelector(targetSel) : null;
      if (newEl) runScripts(newEl);
    } else if (swap === 'beforeend') {
      target.insertAdjacentHTML('beforeend', html);
      runScripts(target);
    } else if (swap === 'afterbegin') {
      target.insertAdjacentHTML('afterbegin', html);
      runScripts(target);
    } else {
      target.innerHTML = html;
      runScripts(target);
    }
    dispatch('htmx:afterSwap', { target: target, elt: el, xhr: detail && detail.xhr ? detail.xhr : null });
  }

  async function submit(el, event) {
    if (event) event.preventDefault();
    const method = el.getAttribute('hx-post') ? 'POST' : 'GET';
    let url = el.getAttribute('hx-post') || el.getAttribute('hx-get');
    const targetSel = el.getAttribute('hx-target');
    const swap = el.getAttribute('hx-swap') || 'innerHTML';
    const indicatorSel = el.getAttribute('hx-indicator') || '';
    const target = targetSel ? document.querySelector(targetSel) : el;
    const indicator = indicatorSel ? document.querySelector(indicatorSel) : null;
    const options = { method: method };
    const detail = { elt: el, target: target, shouldSwap: true, xhr: null };
    dispatch('htmx:beforeRequest', detail);
    if (indicator) indicator.classList.add('htmx-request');
    if (method === 'POST') {
      options.body = el.tagName === 'FORM' ? new FormData(el) : new URLSearchParams();
    } else if (el.tagName === 'FORM') {
      const params = new URLSearchParams();
      for (const [k, v] of new FormData(el)) {
        if (typeof v === 'string') params.append(k, v);
      }
      const qs = params.toString();
      if (qs) url += (url.includes('?') ? '&' : '?') + qs;
    }
    try {
      const response = await fetch(url, options);
      detail.xhr = response;
      if (response.redirected) {
        window.location.href = response.url;
        return;
      }
      const html = await response.text();
      detail.xhr = { responseText: html, status: response.status };
      dispatch('htmx:beforeSwap', detail);
      if (detail.shouldSwap === false) {
        dispatch('htmx:afterRequest', detail);
        return;
      }
      await swapTarget(target, targetSel, swap, html, detail, el);
      dispatch('htmx:afterRequest', { target: target, elt: el, xhr: detail.xhr });
    } finally {
      if (indicator) indicator.classList.remove('htmx-request');
    }
  }

  window.htmx = window.htmx || {};
  window.htmx.ajax = async function (method, url, opts) {
    const options = opts || {};
    const swap = options.swap || 'innerHTML';
    const targetSel = typeof options.target === 'string' ? options.target : '';
    const target = targetSel ? document.querySelector(targetSel) : null;
    const detail = { elt: null, target: target, shouldSwap: true, xhr: null };
    dispatch('htmx:beforeRequest', detail);
    const response = await fetch(url, { method: (method || 'GET').toUpperCase() });
    if (response.redirected) {
      window.location.href = response.url;
      return;
    }
    const html = await response.text();
    detail.xhr = { responseText: html, status: response.status };
    dispatch('htmx:beforeSwap', detail);
    if (detail.shouldSwap === false) {
      dispatch('htmx:afterRequest', { target: target, elt: null, xhr: detail.xhr });
      return;
    }
    await swapTarget(target, targetSel, swap, html, detail, null);
    dispatch('htmx:afterRequest', { target: target, elt: null, xhr: detail.xhr });
  };

  document.addEventListener('click', function (event) {
    const el = event.target.closest('[hx-get]:not(form), [hx-post]:not(form)');
    if (el) submit(el, event);
  });
  document.addEventListener('submit', function (event) {
    const el = event.target.closest('form[hx-get], form[hx-post]');
    if (el) submit(el, event);
  });
  document.addEventListener('change', function (event) {
    const self = event.target.closest('[hx-trigger~="change"]');
    if (self && (self.getAttribute('hx-get') || self.getAttribute('hx-post'))) {
      submit(self, event);
      return;
    }
    const form = event.target.closest('form[hx-trigger~="change"]');
    if (form) submit(form, event);
  });
})();
